      penaltyFixed: { de: "Fixer Entschädigungsbetrag", en: "Fixed penalty amount", zh: "固定违约金金额", ja: "固定手数料額" },
      penaltyModeHelper: { de: "Nur grobe Szenario-Rechnung. Die echte Vorfälligkeitsentschädigung wird von der Bank nach Vertragsdaten, Restlaufzeit, Zinsumfeld und zulässiger Methode berechnet.", en: "Rough scenario calculation only. The real penalty is calculated by the bank based on contract data, remaining term, interest environment and permitted method.", zh: "仅为粗略情景估算。真实提前还款违约金 (Vorfälligkeitsentschädigung) 由银行根据合同数据、剩余期限、利率环境和允许方法计算。", ja: "概算シナリオ計算のみです。実際の期限前返済手数料は、契約データ、残存期間、金利環境、許容される計算方法に基づき銀行が算出します。" },
      penaltyPercentLabel: { de: "Benutzerdefinierte Entschädigung", en: "Custom penalty", zh: "自定义违约金", ja: "カスタム手数料" },
      fixedPenaltyLabel: { de: "Fixe Entschädigung", en: "Fixed penalty", zh: "固定违约金", ja: "固定手数料" },
      overviewEyebrow: { de: "Übersicht", en: "Overview", zh: "总览", ja: "概要" },
      overviewTitle: { de: "Finanzierungsübersicht", en: "Financing Overview", zh: "融资总览", ja: "融資概要" },
      overviewCopy: { de: "Gesamtüberblick über Kapitalstruktur und Rückzahlungsstrategie.", en: "Overview of capital structure and repayment strategy.", zh: "资金结构与还款策略总览。", ja: "資金構成と返済戦略の全体像。" },
      amortizationEyebrow: { de: "Amortisation", en: "Amortization", zh: "还款", ja: "返済" },
      amortizationTitle: { de: "Jährliche Rückzahlungsdetails", en: "Annual Repayment Details", zh: "逐年还款明细", ja: "年次返済詳細" },
      amortizationCopy: { de: "Jährliche Cashflow-Sicht: reguläre Zahlungen, Zinsen, Tilgung, Sondertilgung und Hinweise.", en: "Annual cashflow view: regular payments, interest, principal, special repayment and notes.", zh: "年度现金流视角：常规月供、当年利息、当年还本、特别还款 (Sondertilgung) 和关键备注。", ja: "通常返済、利息、元本返済、特別返済、メモを年次キャッシュフローで表示します。" },
      downloadCsvButton: { de: "CSV exportieren", en: "Export CSV", zh: "导出 CSV", ja: "CSVをエクスポート" },
