      warningRepaymentNotEffective: { de: "Die aktuelle Monatsrate deckt fast nur die Zinsen; die Restschuld sinkt nicht wirksam.", en: "The current monthly payment barely covers interest; principal will not decrease effectively.", zh: "当前月供几乎只够支付利息，贷款本金不会有效下降。", ja: "現在の月々返済額はほぼ利息のみをカバーしており、残債は有効に減りません。" },
      warningBelowMonthlyInterest: { de: "Die Monatsrate liegt unter dem anfänglichen Monatszins; das Darlehen reduziert sich nicht normal.", en: "Monthly payment is below first-month interest; the loan will not decrease normally.", zh: "月供低于首月利息，贷款不会正常减少。", ja: "月々返済額が初月利息を下回っており、ローンは通常どおり減りません。" },
